import React from 'react';
import ReactDOM from 'react-dom/client'; // note o '/client'

// abaixo estamos criando um componente personalizado. A primeira letra do nome deve ser maiúscula. O nome do arquivo pode ser minúsculo.
import Primeiro from './componentes/Primeiro';
import BomDia from './componentes/BomDia';

// o import abaixo tamém foi feito atraves de um export default no arquivo "componentes/Multiplos". Podemos usar o import aqui com um nome de componente que no caso é "Saudacao". Assim podemos chamar ele através do <Saudacao.BoaTarde nome="Juca"/> pdemos usar o destructor usado o {BoaTarde, BoaNoite} e chamar através do <BoaTarde nome="Ana" />
import Multi, {BoaTarde, BoaNoite} from './componentes/Multiplos' // importa componentes multiplos de um único arquivo. Esse documento possui 2 exports

import Saudacao from './componentes/Saudacao';

// abaixo esta a forma de importar sem o destructor criando um nome para o componente personalizado e usando como no exemplo <Saudacao.BoaTarde nome="Juca"/>
//import Saudacao from './componentes/Multiplos'

// abaixo, é feita a renderização do conteudo do componente que foi definido no arquivo "componentes/primeiro"
ReactDOM.createRoot(document.getElementById('root')).render(
    // <> </> é chamado de React Fragment, e serve para agrupar elementos sem adicionar tags extras no DOM.
    // <div> <div/> pode ser utilizado no lugar de React Fragment, e serve para agrupar elementos só que adicionando tags extras no DOM que serão as div.
    <>
        <Primeiro />
        <BomDia nome="Jorge Alan" idade={43} saudacao="meu amigo" />
        <div>
            <BoaTarde nome="Ana" />
            <BoaNoite nome="Bia" />
        </div>
        <div>
            <Multi.BoaTarde nome="Juca"/>
        </div>
        <div>
            <Saudacao tipo="Bom dia" nome="João" />
        </div>
    </>
    );

// a linha comentada abaixo vai fazer com que seja inserido o conteúdo no browser com o componente não personalizado que é o <h1>React</h1>, porque o conteúdo dentro da tag não é referente a um import de um arquivo que recebeu um nome. 
// ReactDOM.createRoot(document.getElementById('root')).render(<h1>React</h1>);

// A linha acima também pode ser usada da forma abaixo:
/* const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(<h1>React</h1>); */
